corrected_fix:
[HttpPost("process")]
public async Task<IActionResult> ProcessData([FromBody] DataPayload payload)
{
    using var dataStream = new MemoryStream(payload.Bytes);
    var processor = new LegacyDataProcessor(dataStream);
    await processor.RunAsync();
    return Ok();
}
